  onUpdateExportPermission: (username: string, canExport: boolean) => void;
  parts: DBItem[];
  workplaces: DBItem[];
  missingReasons: DBItem[];
  onAddPart: (val: string, desc?: string) => void;
  onBatchAddParts: (vals: string[]) => void;
  onDeletePart: (val: string) => void;
  onDeleteAllParts: () => void;
  onAddWorkplace: (val: string, time?: number, x?: number, y?: number) => void;
  onUpdateWorkplace: (id: string, updates: Partial<DBItem>) => void;
  onBatchAddWorkplaces: (vals: string[]) => void;
  onDeleteWorkplace: (id: string) => void;
  onDeleteAllWorkplaces: () => void;
  onAddMissingReason: (val: string) => void;
  logisticsOperations: DBItem[];
  onAddLogisticsOperation: (val: string, time?: number, dist?: number) => void; 
  onUpdateLogisticsOperation: (id: string, updates: Partial<DBItem>) => void;
  onDeleteLogisticsOperation: (id: string) => void;
  mapSectors: MapSector[];
  onAddMapSector: (name: string, x: number, y: number, color?: string) => void;
  onDeleteMapSector: (id: string) => void;
  onUpdateMapSector: (id: string, updates: Partial<MapSector>) => void;
  partRequests: PartRequest[];
  onRequestPart: (part: string) => Promise<boolean>;
  onApprovePartRequest: (req: PartRequest) => void;
  onRejectPartRequest: (id: string) => void;
  breakSchedules: BreakSchedule[];
  systemBreaks: SystemBreak[];
  isBreakActive: boolean;
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  bomMap: Record<string, BOMComponent[]>;
  bomRequests: any[];
  onAddBOMItem: (parent: string, child: string, qty: number) => void;
  onBatchAddBOMItems: (vals: string[]) => void;
  onDeleteBOMItem: (parent: string, child: string) => void;
  onDeleteAllBOMItems: () => void;
  onRequestBOM: (parent: string) => Promise<boolean>;
  onApproveBOMRequest: (req: any) => void;
  onRejectBOMRequest: (id: string) => void;
  roles: Role[];
  permissions: Permission[];
  onAddRole: (name: string) => void;
  onDeleteRole: (id: string) => void;
  onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
  notifications: AppNotification[];
  onClearNotification: (id: string) => void;
  installPrompt: any;
  onInstallApp: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  dbLoadWarning: boolean;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  settings?: any;
}

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
  const { 
    currentUser, currentUserRole, onLogout, tasks, draftTasks, onAddTask, onUpdateTask, roles, permissions,
    notifications, onClearNotification, installPrompt, onInstallApp, parts, workplaces,
    onToggleTask, onEditTask, onDeleteTask, onToggleMissing, onSetInProgress, onToggleManualBlock, onExhaustSearch, onMarkAsIncorrect, onAddNote, onReleaseTask, missingReasons,
    users,
    onApprovePartRequest, onRejectPartRequest,
    onArchiveTasks, onDailyClosing, onWeeklyClosing, fetchSanons,
    breakSchedules,
    bomMap, bomRequests, onApproveBOMRequest, onRejectBOMRequest,
    onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword,
    systemConfig, onUpdateSystemConfig,
    dbLoadWarning, onGetDocCount, onPurgeOldTasks, onExportTasksJSON,
    mapSectors, settings
  } = props;

  const { t, language, setLanguage } = useLanguage();
  const [activeTab, setActiveTab] = useState<'entry' | 'tasks' | 'settings' | 'analytics' | 'bom' | 'missing' | 'logistics' | 'permissions' | 'inventory' | 'catalog'>('entry');
  const [taskSearchQuery, setTaskSearchQuery] = useState('');
  const [entryMode, setEntryMode] = useState<'production' | 'logistics'>('production');

  // STAVY PRE SEKTOR PICKER
  const [pickingTask, setPickingTask] = useState<Task | null>(null);

  const [selectedPart, setSelectedPart] = useState<string | null>(null);
  const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);

  // Logistics States
  const [logisticsRef, setLogisticsRef] = useState('');
  const [logisticsOp, setLogisticsOp] = useState('');
  const [logisticsPlate, setLogisticsPlate] = useState('');
  const [sourceSector, setSourceSector] = useState<string | null>(null);
  const [targetSector, setTargetSector] = useState<string | null>(null);

  const [quantity, setQuantity] = useState<string>('');
  const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
  const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);

  const unitLock = useMemo(() => {
    if (entryMode === 'logistics' || !selectedPart) return null;
    const partData = parts.find(p => p.value === selectedPart);
    const desc = partData?.description || '';
    if (desc.includes('S0001S')) return 'pcs';
    if (desc.includes('S0002S')) return 'boxes';
    if (desc.includes('S0003S')) return 'pallet';
    return null;
  }, [selectedPart, entryMode, parts]);

  useEffect(() => { if (unitLock) setQuantityUnit(unitLock); }, [unitLock]);

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = useCallback((permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) return true;
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  }, [currentUserRole, currentRoleId, permissions]);

  const resolveName = useCallback((username?: string | null) => {
      if (!username) return '-';
      const u = users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  }, [users]);

  const logisticsOperationsList = useMemo(() => props.logisticsOperations || [], [props.logisticsOperations]);

  const handleAdd = () => {
    if (entryMode === 'production') {
        if (!selectedPart || !selectedWorkplace || !quantity) { alert(t('fill_all_fields')); return; }
        // Pass empty note and isProduction = true
        onAddTask(selectedPart, selectedWorkplace, quantity, quantityUnit, priority, false, '', true);
    } else {
        if (!logisticsRef || !logisticsOp || !quantity) { alert(t('fill_all_fields')); return; }
        // Pass source/target sectors for logistics
        onAddTask(logisticsRef, logisticsOp, quantity, quantityUnit, priority, true, logisticsPlate, false, sourceSector || undefined, targetSector || undefined);
    }

    // Reset Form
    setSelectedPart(null); 
    setSelectedWorkplace(null); 
    setLogisticsRef(''); 
    setLogisticsOp(''); 
    setLogisticsPlate(''); 
    setSourceSector(null);
    setTargetSector(null);
    setQuantity('');
    setPriority('NORMAL'); 
    setShowSuccessMessage(true); 
    setTimeout(() => setShowSuccessMessage(false), 2000);
  };

  // LOGIKA KONTROLY SEKTORA PRED DOKONČENÍM
  const handleCompleteWithSectorCheck = (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;

    // Ak je to výrobná úloha, ide sa dokončiť (isDone je false) a chýba priradený sektor:
    if (!task.isLogistics && !task.isDone && !task.pickedFromSectorId) {
        setPickingTask(task);
        return;
    }
    onToggleTask(id);
  };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-white">
      <AppHeader currentUser={currentUser} currentUserRole={currentUserRole} users={users} onLogout={onLogout} language={language} setLanguage={setLanguage} t={t} isFullscreen={false} onToggleFullscreen={()=>{}} installPrompt={installPrompt} onInstallApp={onInstallApp} hasPermission={hasPermission} resolveName={resolveName} />

      {showSuccessMessage && (
        <div className="fixed top-24 right-6 bg-green-600 text-white px-6 py-4 rounded-xl shadow-2xl z-50 animate-bounce font-black tracking-widest">✓ {t('sent_msg')}</div>
      )}

      <TabNavigator activeTab={activeTab} setActiveTab={setActiveTab} hasPermission={hasPermission} t={t} counts={{ tasks: (tasks || []).filter(t=>!t.isDone).length, pendingRequests: (props.partRequests?.length || 0) + (props.bomRequests?.length || 0) }} />

      <div className="flex-grow overflow-y-auto p-3 md:p-8 custom-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
          {activeTab === 'entry' && (
            <ProductionEntry 
                mode={entryMode} setMode={setMode => { setEntryMode(setMode); setQuantityUnit(setMode === 'logistics' ? 'pallet' : 'pcs'); }} 
                selectedPart={selectedPart} setSelectedPart={setSelectedPart} 
                selectedWorkplace={selectedWorkplace} setSelectedWorkplace={setSelectedWorkplace} 
                logisticsRef={logisticsRef} setLogisticsRef={setLogisticsRef} 
                logisticsPlate={logisticsPlate} setLogisticsPlate={setLogisticsPlate} 
                logisticsOp={logisticsOp} setLogisticsOp={setLogisticsOp} 
                sourceSector={sourceSector} setSourceSector={setSourceSector}
                targetSector={targetSector} setTargetSector={setTargetSector}
                quantity={quantity} setQuantity={setQuantity} 
                quantityUnit={quantityUnit} setQuantityUnit={setQuantityUnit} 
                priority={priority} setPriority={setPriority} 
                parts={(parts || []).map(p => p.value)} workplaces={workplaces} 
                logisticsOperationsList={logisticsOperationsList} 
                mapSectors={mapSectors}
                t={t} language={language} hasPermission={hasPermission} 
                handleAdd={handleAdd} onRequestPart={props.onRequestPart} 
                isUnitLocked={!!unitLock} 
            />
          )}
          {activeTab === 'analytics' && (
            <AnalyticsTab 
              tasks={tasks} 
              draftTasks={draftTasks}
              onFetchArchivedTasks={props.onFetchArchivedTasks} 
              fetchSanons={fetchSanons} 
              settings={settings} 
              systemBreaks={props.systemBreaks} 
              resolveName={resolveName} 
              mapSectors={mapSectors} 
              workplaces={workplaces} 
              systemConfig={systemConfig} 
              logisticsOperations={logisticsOperationsList} 
              users={users} 
              currentUser={currentUser} 
              currentUserRole={currentUserRole} 
              hasPermission={hasPermission} 
            />
          )}
          {activeTab === 'settings' && <SettingsTab hasPermission={hasPermission} currentUserRole={currentUserRole} users={users} onAddUser={props.onAddUser} onUpdatePassword={props.onUpdatePassword} onUpdateNickname={props.onUpdateNickname} onUpdateUserRole={props.onUpdateUserRole} onDeleteUser={props.onDeleteUser} onUpdateExportPermission={props.onUpdateExportPermission} parts={parts} workplaces={workplaces} missingReasons={missingReasons} onAddPart={props.onAddPart} onBatchAddParts={props.onBatchAddParts} onDeletePart={props.onDeletePart} onDeleteAllParts={props.onDeleteAllParts} onAddWorkplace={props.onAddWorkplace} onUpdateWorkplace={props.onUpdateWorkplace} onBatchAddWorkplaces={props.onBatchAddWorkplaces} onDeleteWorkplace={props.onDeleteWorkplace} onDeleteAllWorkplaces={props.onDeleteAllWorkplaces} onAddMissingReason={props.onAddMissingReason} onDeleteMissingReason={props.onDeleteMissingReason} logisticsOperations={logisticsOperationsList} onAddLogisticsOperation={props.onAddLogisticsOperation} onUpdateLogisticsOperation={props.onUpdateLogisticsOperation} onDeleteLogisticsOperation={props.onDeleteLogisticsOperation} mapSectors={mapSectors} onAddMapSector={props.onAddMapSector} onDeleteMapSector={props.onDeleteMapSector} onUpdateMapSector={props.onUpdateMapSector} partRequests={props.partRequests} onApprovePartRequest={onApprovePartRequest} onRejectPartRequest={onRejectPartRequest} onArchiveTasks={onArchiveTasks} onDailyClosing={props.onDailyClosing} onWeeklyClosing={props.onWeeklyClosing} fetchSanons={fetchSanons} breakSchedules={breakSchedules} onAddBreakSchedule={props.onAddBreakSchedule} onDeleteBreakSchedule={props.onDeleteBreakSchedule} bomMap={bomMap} bomRequests={bomRequests} onAddBOMItem={props.onAddBOMItem} onBatchAddBOMItems={props.onBatchAddBOMItems} onDeleteBOMItem={props.onDeleteBOMItem} onDeleteAllBOMItems={props.onDeleteAllBOMItems} onApproveBOMRequest={onApproveBOMRequest} onRejectBOMRequest={onRejectBOMRequest} roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} installPrompt={null} onInstallApp={()=>{}} systemConfig={systemConfig} onUpdateSystemConfig={onUpdateSystemConfig} dbLoadWarning={dbLoadWarning} resolveName={resolveName} onGetDocCount={onGetDocCount} onPurgeOldTasks={onPurgeOldTasks} onExportTasksJSON={onExportTasksJSON} onUpdateAdminKey={props.onUpdateAdminKey} onToggleAdminLock={props.onToggleAdminLock} />}
          {activeTab === 'tasks' && (
            <div className="animate-fade-in pb-20">
              <div className="mb-6 flex justify-center">
                <input 
                  type="text" 
                  value={taskSearchQuery} 
                  onChange={e => setTaskSearchQuery(e.target.value)} 
                  className="w-full max-w-lg h-12 px-6 bg-gray-800 border border-gray-700 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase" 
                  placeholder={t('task_search_placeholder')} 
                />
              </div>
              <TaskList 
                currentUser={currentUserRole} 
                currentUserName={currentUser} 
                tasks={(tasks || []).filter(t => { 
                  const q = taskSearchQuery.toLowerCase(); 
                  return (t.partNumber && t.partNumber.toLowerCase().includes(q)) || (t.text && t.text.toLowerCase().includes(q)) || (t.workplace && t.workplace.toLowerCase().includes(q)); 
                })} 
                onToggleTask={handleCompleteWithSectorCheck} 
                onEditTask={onEditTask} 
                onDeleteTask={onDeleteTask} 
                onToggleMissing={onToggleMissing} 
                onSetInProgress={onSetInProgress} 
                onToggleBlock={props.onToggleBlock} 
                onToggleManualBlock={onToggleManualBlock} 
                onExhaustSearch={onExhaustSearch} 
                onMarkAsIncorrect={onMarkAsIncorrect} 
                onAddNote={onAddNote} 
                onReleaseTask={onReleaseTask} 
                onAuditPart={props.onStartAudit}
                onFinishAudit={props.onFinishAudit} 
                resolveName={resolveName} 
                missingReasons={missingReasons} 
                hasPermission={hasPermission} 
              />
            </div>
          )}
          {activeTab === 'bom' && <BOMScreen parts={parts} workplaces={workplaces} bomMap={bomMap} onAddTask={onAddTask} onRequestBOM={props.onRequestBOM} t={t} language={language} />}
          {activeTab === 'missing' && <MissingItemsTab tasks={tasks} onDeleteMissingItem={props.onDeleteMissingItem} hasPermission={hasPermission} resolveName={resolveName} />}
          {activeTab === 'inventory' && <InventoryTab currentUser={currentUser} tasks={tasks} onAddTask={onAddTask} onUpdateTask={onUpdateTask} onToggleTask={onToggleTask} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} parts={(parts || []).map(p=>p.value)} onRequestPart={props.onRequestPart} resolveName={resolveName} />}
          {activeTab === 'logistics' && <LogisticsCenterTab tasks={tasks} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} resolveName={resolveName} />}
          {activeTab === 'permissions' && <PermissionsTab roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} onVerifyAdminPassword={onVerifyAdminPassword} />}
          {activeTab === 'catalog' && <PartCatalogTab parts={parts} onSelectPart={p => { setSelectedPart(p.value); setActiveTab('entry'); }} />}
          </div>
      </div>

      {pickingTask && createPortal(
          <SectorPickerModal 
              task={pickingTask}
              mapSectors={props.mapSectors}
              onClose={() => setPickingTask(null)}
              onConfirm={(sectorId) => {
                  onUpdateTask(pickingTask.id, { pickedFromSectorId: sectorId });
                  onToggleTask(pickingTask.id);
                  setPickingTask(null);
              }}
          />,
          document.body
      )}
    </div>
  );
};

export default PartSearchScreen;

import React from 'react';
import PartNumberInput from '../PartNumberInput';
import { DBItem, PriorityLevel, MapSector } from '../../types/appTypes';

interface ProductionEntryProps {
  mode: 'production' | 'logistics';
  setMode: (mode: 'production' | 'logistics') => void;
  selectedPart: string | null;
  setSelectedPart: (part: string | null) => void;
  selectedWorkplace: string | null;
  setSelectedWorkplace: (val: string | null) => void;
  logisticsRef: string;
  setLogisticsRef: (val: string) => void;
  logisticsPlate: string;
  setLogisticsPlate: (val: string) => void;
  logisticsOp: string;
  setLogisticsOp: (val: string) => void;
  sourceSector: string | null;
  setSourceSector: (val: string | null) => void;
  targetSector: string | null;
  setTargetSector: (val: string | null) => void;
  quantity: string;
  setQuantity: (val: string) => void;
  quantityUnit: 'pcs' | 'boxes' | 'pallet';
  setQuantityUnit: (val: 'pcs' | 'boxes' | 'pallet') => void;
  priority: PriorityLevel;
  setPriority: (val: PriorityLevel) => void;
  parts: string[];
  workplaces: DBItem[];
  logisticsOperationsList: DBItem[];
  mapSectors: MapSector[];
  t: (key: any, params?: any) => string;
  language: string;
  hasPermission: (perm: string) => boolean;
  handleAdd: () => void;
  onRequestPart: (part: string) => Promise<boolean>;
  isUnitLocked?: boolean;
}

const PlusIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
  </svg>
);

const ProductionEntry: React.FC<ProductionEntryProps> = ({
  mode, setMode, selectedPart, setSelectedPart, selectedWorkplace, setSelectedWorkplace,
  logisticsRef, setLogisticsRef, logisticsPlate, setLogisticsPlate, logisticsOp, setLogisticsOp, 
  sourceSector, setSourceSector, targetSector, setTargetSector,
  quantity, setQuantity, quantityUnit, setQuantityUnit, priority, setPriority, parts, workplaces,
  logisticsOperationsList, mapSectors, t, language, hasPermission, handleAdd, onRequestPart, isUnitLocked
}) => {
  const inputBaseClass = "w-full h-12 bg-gray-700 border border-gray-600 rounded-lg px-4 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-base";

  const showSectorSelectors = React.useMemo(() => {
      const op = logisticsOp.toUpperCase();
      return op.includes('PRESUN') || op.includes('MOVE');
  }, [logisticsOp]);

  return (
    <div className="h-full flex flex-col items-center animate-fade-in pb-20">
      <div className="w-full max-w-2xl">
        <div className="bg-gray-800 p-5 sm:p-8 rounded-xl shadow-lg border border-gray-700 relative">
          {hasPermission('perm_logistics_mode') && (
            <div className="flex justify-center mb-8 z-10 relative">
              <div className="bg-gray-900 p-1.5 rounded-xl flex border border-gray-600 shadow-inner h-14">
                <button 
                  onClick={() => setMode('production')} 
                  className={`px-5 sm:px-8 rounded-lg font-bold text-base transition-all duration-200 flex items-center gap-2 ${mode === 'production' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
                >
                  🏭 {t('mode_production')}
                </button>
                <button 
                  onClick={() => setMode('logistics')} 
                  className={`px-5 sm:px-8 rounded-lg font-bold text-base transition-all duration-200 flex items-center gap-2 ${mode === 'logistics' ? 'bg-sky-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
                >
                  🚛 {t('mode_logistics')}
                </button>
              </div>
            </div>
          )}
          <h1 className={`text-3xl sm:text-4xl font-extrabold text-center mb-3 ${mode === 'production' ? 'text-teal-400' : 'text-sky-400'}`}>
            {t('search_title')}
          </h1>
          <p className="text-gray-400 text-center mb-8 text-base">{t('search_subtitle')}</p>
          <div className="space-y-6 sm:space-y-8">
            {mode === 'production' ? (
              <>
                <div>
                  <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">
                    {t('part_number')} <span className="text-teal-500">*</span>
                  </label>
                  <PartNumberInput 
                    parts={parts} 
                    onPartSelect={setSelectedPart} 
                    placeholder={t('part_placeholder')} 
                    value={selectedPart} 
                    onRequestPart={onRequestPart} 
                  />
                </div>
                <div>
                  <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">
                    {t('workplace')} <span className="text-teal-500">*</span>
                  </label>
                  <div className="relative">
                    <select 
                      value={selectedWorkplace || ''} 
                      onChange={(e) => setSelectedWorkplace(e.target.value)} 
                      className="block appearance-none w-full h-12 bg-gray-700 border border-gray-600 text-white px-4 pr-10 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500 transition-colors font-mono uppercase text-base"
                    >
                      <option value="" className="font-sans normal-case">{t('workplace_placeholder')}</option>
                      {workplaces.map((wp) => (<option key={wp.id} value={wp.value}>{wp.value}</option>))}
                    </select>
                    <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-4 text-gray-400">
                      <svg className="fill-current h-5 w-5" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                    </div>
                  </div>
                </div>
              </>
            ) : (
              <>
                <div>
                  <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">
                    {t('log_reference')} <span className="text-sky-500">*</span>
                  </label>
                  <input 
                    type="text" 
                    value={logisticsRef} 
                    onChange={(e) => setLogisticsRef(e.target.value.toUpperCase())} 
                    placeholder={t('log_reference_place')} 
                    className={`${inputBaseClass} focus:ring-sky-500`} 
                  />
